7	// Helpers
8	function headerCell(text, width) {
9	  return new TableCell({
10	    width: { size: width, type: WidthType.PERCENTAGE },
11	    shading: { type: ShadingType.SOLID, color: '1a5276' },
12	    children: [new Paragraph({ children: [new TextRun({ text, bold: true, color: 'FFFFFF', size: 20, font: 'Microsoft YaHei' })], spacing: { before: 40, after: 40 } })],
13	  });
14	}
15	
16	function cell(text, width) {
17	  return new TableCell({
18	    width: { size: width, type: WidthType.PERCENTAGE },
19	    children: [new Paragraph({ children: [new TextRun({ text, size: 19, font: 'Microsoft YaHei' })], spacing: { before: 30, after: 30 } })],
20	  });
21	}
22	
23	function heading(text, level) {
24	  const sizes = {1: 32, 2: 28, 3: 24};
25	  return new Paragraph({ heading: level, children: [new TextRun({ text, bold: true, font: 'Microsoft YaHei', size: sizes[level] || 24 })], spacing: { before: 200, after: 100 } });
26	}
27	
28	function para(text, opts = {}) {
29	  return new Paragraph({
30	    children: [new TextRun({ text, size: 21, font: 'Microsoft YaHei', ...opts })],
31	    spacing: { before: 60, after: 60 }
32	  });
33	}
34	
35	function boldPara(label, text) {
36	  return new Paragraph({
37	    children: [
38	      new TextRun({ text: label, bold: true, size: 21, font: 'Microsoft YaHei' }),
39	      new TextRun({ text, size: 21, font: 'Microsoft YaHei' })
40	    ],
41	    spacing: { before: 40, after: 40 }
