43	}
44	
45	// Build document
46	const children = [];
47	
48	// Title
49	children.push(
50	  new Paragraph({ heading: HeadingLevel.HEADING_1, children: [new TextRun({ text: '外贸跟进方案 — P0客户完整分析', bold: true, font: 'Microsoft YaHei', size: 36 })], spacing: { after: 100 } }),
51	  para('生成日期：2026年4月30日'),
