56	  para('')
57	);
58	
59	// Priority summary
60	children.push(heading('执行优先级概览', 1));
61	const pLevels = [
62	  { title: '🔴 第一梯队：今天必须处理（2人）', data: data.summary.urgent },
63	  { title: '🟡 第二梯队：48h内处理（3人）', data: data.summary.high },
64	  { title: '🟢 第三梯队：本周内处理（4人）', data: data.summary.medium },
65	  { title: '⚪ 第四梯队：按需轻触达（5人）', data: data.summary.low }
66	];
67	
68	for (const level of pLevels) {
69	  children.push(heading(level.title, 2));
70	  const rows = [new TableRow({ children: [headerCell('客户', 20), headerCell('执行动作', 65), headerCell('时限', 15)] })];
71	  for (const item of level.data) {
72	    rows.push(new TableRow({ children: [cell(item.name, 20), cell(item.action, 65), cell(item.urgency, 15)] }));
73	  }
74	  children.push(new Table({ rows, width: { size: 100, type: WidthType.PERCENTAGE } }));
75	  children.push(para(''));
76	}
77	
78	children.push(new Paragraph({ children: [new PageBreak()] }));
79	children.push(heading('逐客深度分析', 1));
80	
81	// Each customer
82	for (let i = 0; i < data.customers.length; i++) {
83	  const c = data.customers[i];
84	  children.push(heading(`${i + 1}. ${c.name}  |  ${c.tier}级  |  ${c.country}  |  ${c.priority}`, 2));
85	
