87	    new TableRow({ children: [headerCell('字段', 15), headerCell('内容', 85)] }),
88	    new TableRow({ children: [cell('阶段诊断', 15), cell(c.stage, 85)] }),
89	    new TableRow({ children: [cell('消息数量', 15), cell(c.messages + '条', 85)] }),
90	    new TableRow({ children: [cell('沟通语言', 15), cell(c.lang, 85)] }),
91	    new TableRow({ children: [cell('钩子方案', 15), cell(c.hook || '不使用钩子（直接回答/推下一步）', 85)] }),
92	  ];
93	  children.push(new Table({ rows: infoRows, width: { size: 100, type: WidthType.PERCENTAGE } }));
94	  children.push(para(''));
95	
96	  children.push(heading('客户概况', 3));
97	  children.push(para(c.summary));
98	
99	  children.push(heading('阶段分析', 3));
100	  children.push(para(c.stageDetail));
101	
102	  if (c.blockage) {
103	    children.push(heading('卡点诊断', 3));
104	    children.push(para(c.blockage));
105	  }
106	
107	  children.push(heading('下一步策略', 3));
108	  children.push(para(c.nextStep));
109	
110	  children.push(heading('跟进话术', 3));
111	  children.push(boldPara('发送语言：', c.script.translateTo));
112	  children.push(new Paragraph({
113	    children: [new TextRun({ text: c.script.text, size: 21, font: 'Microsoft YaHei', italics: true })],
114	    spacing: { before: 80, after: 80 },
115	    border: {
116	      top: { style: BorderStyle.SINGLE, size: 1, color: '2980b9' },
117	      bottom: { style: BorderStyle.SINGLE, size: 1, color: '2980b9' },
118	      left: { style: BorderStyle.SINGLE, size: 1, color: '2980b9' },
119	      right: { style: BorderStyle.SINGLE, size: 1, color: '2980b9' }
120	    },
121	  }));
122	
123	  if (c.postNote) {
124	    children.push(heading('内部备注', 3));
125	    children.push(para(c.postNote, { color: 'c0392b' }));
126	  }
127	
128	  children.push(new Paragraph({ children: [new PageBreak()] }));
129	}
130	
131	// Appendix
132	children.push(heading('附录：数据来源说明', 1));
133	children.push(para('1. deep_scrape_2026-04-30T07-40-03.json — 最新抓取，40个目标中6个成功，31个被跳过（DOM中未找到）'));
134	children.push(para('2. deep_scrape_2026-04-30T06-12-00.json — 第二次抓取，39个目标中6个成功，33个被跳过'));
135	children.push(para('3. deep_scrape_merged_v2_2026-04-29T13-23-38_cleaned.json — 清洗合并版，29个客户含完整消息'));
136	children.push(para('4. 交叉验证通过：Karl brown、Abdou Salam Kane、Dania Sanchez、Sarah nell roly、yoselyn Rodriguez 出现在两个以上文件中，数据一致'));
137	children.push(para('5. 其余9个客户仅在清洗合并文件中出现，标注"未经交叉验证"'));
138	children.push(para(''));
139	
140	children.push(heading('附录：钩子素材状态速查', 1));
141	const hookRows = [
142	  new TableRow({ children: [headerCell('钩子ID', 25), headerCell('状态', 10), headerCell('本次使用情况', 65)] }),
143	  new TableRow({ children: [cell('hook_pampers_olympic', 25), cell('✅', 10), cell('Karl brown话术中嵌入（帮宝适奥运背书）', 65)] }),
144	  new TableRow({ children: [cell('hook_iso_cert', 25), cell('✅', 10), cell('Lisa Ketelsen话术中提（德国客户重认证）', 65)] }),
145	  new TableRow({ children: [cell('hook_fabric_library', 25), cell('⚠️', 10), cell('martin wamundila使用替代方案（发面料图而非完整可视化库）', 65)] }),
146	  new TableRow({ children: [cell('hook_disney_ip', 25), cell('✅', 10), cell('本次未使用', 65)] }),
147	  new TableRow({ children: [cell('hook_fabric_compare', 25), cell('⚠️', 10), cell('本次未使用（静态对比图可用，视频M06待拍摄）', 65)] }),
148	  new TableRow({ children: [cell('hook_sample_fabric', 25), cell('❌ 禁用', 10), cell('待制备（M10），本次未使用', 65)] }),
149	  new TableRow({ children: [cell('hook_packing_shipping', 25), cell('❌ 禁用', 10), cell('待拍摄（M07），本次未使用', 65)] }),
150	  new TableRow({ children: [cell('hook_production_line', 25), cell('⚠️', 10), cell('本次未使用（已有基础素材但非专业拍摄）', 65)] }),
151	];
152	children.push(new Table({ rows: hookRows, width: { size: 100, type: WidthType.PERCENTAGE } }));
153	
154	// Generate
155	const doc = new Document({ sections: [{ properties: {}, children }] });
156	Packer.toBuffer(doc).then(buffer => {
157	  const outPath = 'C:\\Users\\Administrator\\Desktop\\外贸跟进方案_P0完整分析_2026-04-30.docx';
